data.content:
**MSTest does have these assertions** — they're available in MSTest 3.x+. Here's what to use:

### Comparison Assertions

```csharp
Assert.IsGreaterThan(lowerBound, actual);
Assert.IsLessThan(upperBound, actual);
Assert.IsInRange(actual, low, high);
```

### For Your `ScoreCalculator`

```csharp
[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calc = new();

    // ── CalculatePercentage ──

    [TestMethod]
    [DataRow(5, 10, 50.0)]
    [DataRow(10, 10, 100.0)]
    [DataRow(0, 10, 0.0)]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(
        int correct, int total, double expected)
    {
        Assert.AreEqual(expected, _calc.CalculatePercentage(correct, total));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(11, 10));
    }

    // ── GetGrade boundary tests ──

    [TestMethod]
    [DataRow(90.0, "A")]
    [DataRow(89.99, "B")]
    [DataRow(80.0, "B")]
    [DataRow(79.99, "C")]
    [DataRow(70.0, "C")]
    [DataRow(69.99, "D")]
    [DataRow(60.0, "D")]
    [DataRow(59.99, "F")]
    public void GetGrade_AtBoundary_ReturnsCorrectGrade(
        double percentage, string expected)
    {
        Assert.AreEqual(expected, _calc.GetGrade(percentage));
    }

    // ── NormalizeScore ──

    [TestMethod]
    public void NormalizeScore_HalfOfMax_Returns50()
    {
        Assert.AreEqual(50.0, _calc.NormalizeScore(50, 100));
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_ClampedTo100()
    {
        var result = _calc.NormalizeScore(150, 100);
        Assert.AreEqual(100.0, result);
    }

    [TestMethod]
    public void NormalizeScore_Result_IsInValidRange()
    {
        var result = _calc.NormalizeScore(37, 80);

        // ✅ Comparison assertions from MSTest 3.x
        Assert.IsGreaterThan(0.0, result);    // result > 0
        Assert.IsLessThan(100.0, result);     // result < 100
        Assert.IsInRange(result, 0.0, 100.0); // 0 ≤ result ≤ 100
    }

    [TestMethod]
    public void NormalizeScore_NegativeRaw_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(-1, 100));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMax_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(50, 0));
    }
}
```

### Key Points

| Assertion | Meaning |
|---|---|
| `Assert.IsGreaterThan(bound, actual)` | actual > bound |
| `Assert.IsLessThan(bound, actual)` | actual < bound |
| `Assert.IsInRange(actual, low, high)` | low ≤ actual ≤ high |
| `Assert.ThrowsExactly<T>(...)` | Exact exception type |

These require **MSTest 3.x+** — use the `MSTest` metapackage or `MSTest.Sdk`. The boundary tests on `GetGrade` use `[DataRow]` to check both sides of each threshold (e.g., `90.0 → A` vs `89.99 → B`).
